// typed-fetch runtime — thin wrapper around fetch() that parses JSON.
// Types are provided by the TS LS plugin via generated .d.ts, not by this file.
exports.typedFetch = function typedFetch(url, init) {
  return fetch(url, init).then(function (res) {
    if (!res.ok) throw new Error("HTTP " + res.status + ": " + res.statusText);
    return res.json();
  });
};
